        const last = merged[merged.length - 1];

        // Check if current interval overlaps with the last merged interval
        if (current[0] <= last[1]) {
            // Merge intervals
            merged[merged.length - 1] = [last[0], Math.max(last[1], current[1])];
        } else {
            // No overlap, add as new interval
            merged.push(current);
        }
    }

